starterCss:
/* Build a container-style-query system:
   - Wrapper defines --variant custom property
   - Cards adapt their style based on parent's --variant value
   - default: white bg, gray border
   - featured: blue bg, white text
   - danger: red border, red tinted bg */
.csq-wrapper {
  container-type: normal;
  margin-bottom: 12px;
}

referenceSolutions:
.csq-wrapper {
  container-type: normal;
  margin-bottom: 12px;
}
.csq-card {
  padding: 20px;
  border-radius: 8px;
  border: 1px solid rgb(222, 226, 230);
  background-color: rgb(255, 255, 255);
}
.csq-title {
  margin: 0 0 8px;
  font-size: 18px;
}
.csq-text {
  margin: 0;
  color: rgb(108, 117, 125);
  line-height: 1.5;
}
@container style(--variant: featured) {
  .csq-card {
    background-color: rgb(0, 123, 255);
    border-color: rgb(0, 123, 255);
    color: rgb(255, 255, 255);
  }
  .csq-text {
    color: rgba(255, 255, 255, 0.85);
  }
}
@container style(--variant: danger) {
  .csq-card {
    background-color: rgb(255, 243, 243);
    border-color: rgb(220, 53, 69);
    border-width: 2px;
  }
  .csq-title {
    color: rgb(220, 53, 69);
  }
}

